# Test
# ---------------------------------------------------------------------------


@pytest.mark.parametrize("finalize_on_device", [True, False], ids=["final-txn", "signed-psbt"])
def test_musig2_sp_three_hardware_signers(three_musig_signers, finalize_on_device):
    """
    End-to-end hardware workflow:

      Round 1: Alice -> Bob -> Charlie each add a pubnonce and SP ECDH/DLEQ shares.
      Round 2: Alice -> Bob add partial signatures; Charlie adds the third partial and
               aggregates the MuSig2 signature.

    Charlie's last step runs as one of two cases (CC finalizes only as part of the final
    signature, and his nonce is one-shot, so each output needs its own fresh run):
      - finalize_on_device=True : Charlie signs with finalize=True -> broadcast-ready txn.
      - finalize_on_device=False: Charlie signs with finalize=False -> fully-signed PSBT.
    """
    if not all(os.path.exists(path) for path in (ROUND1_PSBT, TREASURY_DESC)):
        pytest.skip(f"Three-signer fixtures not found at {DATA_DIR}")

    signers = three_musig_signers
    current = BasicPSBT().parse(_load_psbt(ROUND1_PSBT))
    scan_keys = _get_scan_keys(current)
    assert len(scan_keys) == NUM_RECIPIENTS

    participant_keys = {}

    # Round 1: pass the growing PSBT through three independent hardware devices.
    for expected_count, signer in enumerate(signers, start=1):
        before = current
        expected_title = "OK TO SEND?" if expected_count == len(signers) else "CONTRIBUTE SHARES?"
        signed, story = signer.sign(
            before.as_bytes(),
            expected_title=expected_title,
            finalize=False,
        )
        if expected_title == "CONTRIBUTE SHARES?":
            assert "ECDH shares" in story
            assert "Other signers" in story
        else:
            # Charlie's shares complete ECDH coverage during preview, but his empty device
            # session cache still makes this approval cryptographic Round 1.
            assert "sp1" in story

        current = BasicPSBT().parse(signed)
        _maybe_write_artifact(signed, f"r1-{signer.name.lower()}.psbt")
        participant_keys[signer.name] = _assert_round1_contribution(before, current, signer.name, scan_keys)
        assert len(current.inputs[0].musig_pubnonces) == expected_count
        assert len(current.inputs[0].musig_partial_ecdh_shares) == expected_count * NUM_RECIPIENTS
        assert len(current.inputs[0].musig_partial_dleq_proofs) == expected_count * NUM_RECIPIENTS

    assert len(set(participant_keys.values())) == 3
    assert len(current.inputs[0].musig_pubnonces) == 3
    assert len(current.inputs[0].musig_partial_ecdh_shares) == 3 * NUM_RECIPIENTS
    assert len(current.inputs[0].musig_partial_dleq_proofs) == 3 * NUM_RECIPIENTS

    # Round 2: Alice derives the SP scripts and signs; Bob verifies and signs the same PSBT.
    round2_psbt = current
    expected_scripts = None
    for expected_count, signer in enumerate(signers[:2], start=1):
        signed, story = signer.sign(
            round2_psbt.as_bytes(),
            expected_title="OK TO SEND?",
            finalize=False,
        )
        assert "sp1" in story

        round2_psbt = BasicPSBT().parse(signed)
        _maybe_write_artifact(signed, f"r2-{signer.name.lower()}.psbt")
        _assert_partial_sigs(
            round2_psbt,
            participant_keys,
            [s.name for s in signers[:expected_count]],
        )

        scripts = _sp_scripts(round2_psbt)
        assert len(scripts) == NUM_RECIPIENTS
        assert all(len(script) == 34 and script[0] == 0x51 for script in scripts)
        if expected_scripts is None:
            expected_scripts = scripts
        else:
            assert scripts == expected_scripts

    # Charlie consumes the last secret nonce, adds the final partial, and aggregates the
    # MuSig2 signature.
    charlie = signers[2]
    result, story = charlie.sign(
        round2_psbt.as_bytes(),
        expected_title="OK TO SEND?",
        finalize=finalize_on_device,
    )
    assert "sp1" in story

    if finalize_on_device:
        # Charlie finalizes in the same pass: broadcast-ready transaction.
        _maybe_write_artifact(b2a_hex(result) + b"\n", "musig2-sp-final.hex")
        _assert_final_transaction(result, round2_psbt)
    else:
        # Charlie exports the fully-signed PSBT (all three partials + aggregated key sig).
        complete_psbt = BasicPSBT().parse(result)
        _maybe_write_artifact(result, "musig2-sp-final.psbt")
        _assert_complete_psbt(complete_psbt, participant_keys)
        scripts = _sp_scripts(complete_psbt)
        assert len(scripts) == NUM_RECIPIENTS
        assert scripts == expected_scripts
